#!/bin/bash
cd /opt/super-assistant
echo 'Creating files...'
echo '' | base64 -d > local_claude_worker.py
echo '  OK: local_claude_worker.py'
mkdir -p server
echo '' | base64 -d > server/database.py
echo '  OK: server/database.py'
mkdir -p server\routers
echo '' | base64 -d > server/routers/local_agent_router.py
echo '  OK: server/routers/local_agent_router.py'
mkdir -p server\services
echo '' | base64 -d > server/services/profile_service.py
echo '  OK: server/services/profile_service.py'
echo '' | base64 -d > .env
echo '  OK: .env'
mkdir -p server\services
echo '' | base64 -d > server/services/local_agent_job_service.py
echo '  OK: server/services/local_agent_job_service.py'
mkdir -p app
echo '' | base64 -d > app/local-claude-check.html
echo '  OK: app/local-claude-check.html'
mkdir -p server
echo '' | base64 -d > server/config.py
echo '  OK: server/config.py'
mkdir -p server\schemas
echo '' | base64 -d > server/schemas/local_agent_schemas.py
echo '  OK: server/schemas/local_agent_schemas.py'
mkdir -p server
echo '' | base64 -d > server/main.py
echo '  OK: server/main.py'
echo 'Restarting...'
sudo pkill -f uvicorn 2>/dev/null; sleep 1
nohup python3 -m uvicorn server.main:app --host 0.0.0.0 --port 8000 > /var/log/sa.log 2>&1 &
sleep 2
curl -s http://127.0.0.1:8000/api/health
echo ''
echo 'Check: http://8.163.35.221:8000/local-claude-check.html'

